changeSet.sql:
do $$
begin
    if not exists (
        select 1
        from pg_type t
        join pg_namespace n on n.oid = t.typnamespace
        where n.nspname = 'gmdb'
          and t.typname = 'pub_type'
    ) then
        create type gmdb.pub_type as enum ('BOOK', 'MAG');
    end if;

    if not exists (
        select 1
        from pg_type t
        join pg_namespace n on n.oid = t.typnamespace
        where n.nspname = 'gmdb'
          and t.typname = 'artist_type'
    ) then
        create type gmdb.artist_type as enum ('PERSON', 'BAND');
    end if;
end
$$;
